# Define 2 Pipelines with and without SMOTE

# Pipeline without SMOTE (use original training dataset)
def pipeline_without_SMOTE(classifier):
    return Pipeline(steps=[
        ("transform", data_transformer),
        ("classifier", classifier)
    ])

# Pipeline with SMOTE
