"""#### Functions to Summarize Results"""

def find_best_and_runnerup(metrics, input_df, summary):
    # For each metric, find the best performing label
    for metric in metrics:
        # For cv_time_sec, lower score is better; for all others, higher is better.
        if metric == "cv_time_sec":
            sorted_df = input_df.sort_values(by=metric, ascending=True)
        else:
            sorted_df = input_df.sort_values(by=metric, ascending=False)

        # Get the best and runner-up rows
        best_row = sorted_df.iloc[0]
        runner_up_row = sorted_df.iloc[1] if sorted_df.shape[0] > 1 else best_row

        summary.append({
            "Metric": metric,
            "Best Model": best_row["Label"],
            "Best Score": best_row[metric],
            "Runner Up Model": runner_up_row["Label"],
            "Runner Up Score": runner_up_row[metric]
        })

    # Convert the summary list to a DataFrame
    summary_df = pd.DataFrame(summary)

    return summary_df

def apply_threshold(metrics, results_means_df, min_acc=0.7, min_recall=0.7, test=False):
    # Boolean mask
    if test:
        mask = (results_means_df ["Test Accuracy"] >= min_acc) & (results_means_df["Test Recall"] >= min_recall)
        # Subset the DataFrame
        comparable_results_df = results_means_df[mask].sort_values(by=["Test Recall", "Test Accuracy"], ascending=False)
    else:
        mask = (results_means_df ["mean_accuracy"] >= min_acc) & (results_means_df["mean_recall"] >= min_recall)
        comparable_results_df = results_means_df[mask].sort_values(by=["mean_recall", "mean_accuracy"], ascending=False)
    return comparable_results_df

"""#### Summary of Best & Runner-Up Models"""

