def plot_cm_roc(model_name, y_test, y_pred, y_prob=None):
  fig, axes = plt.subplots(1, 2, figsize=(8,4))

  # Compute confusion matrices
  cm = confusion_matrix(y_test, y_pred)
  cm_normalized = cm.astype('float') / cm.sum(axis=1)[:, np.newaxis]

  # Define confusion matrix labels
  cm_labels = np.array([["TN", "FP"], ["FN", "TP"]])

  # Create annotation array that includes count, row-wise normalized percentage, and cell label
  annot = np.empty_like(cm).astype(str)
  for i in range(cm.shape[0]):
    for j in range(cm.shape[1]):
      annot[i, j] = f"{cm[i, j]} ({cm_normalized[i, j]:.1%})\n{cm_labels[i, j]}"

  # Plot confusion matrix
  sns.heatmap(cm, ax=axes[0], annot=annot, fmt="", cmap=sns.color_palette("ch:s=-.2,r=.6"), cbar=False, annot_kws={'size':10})
  axes[0].set_title(f"Confusion Matrix - {model_name}")
  axes[0].set_xlabel("Predicted")
  axes[0].set_ylabel("Actual")

  # Plot ROC curve
  if y_prob is not None:
    fpr, tpr, _ = roc_curve(y_test, y_prob)
    roc_auc = auc(fpr, tpr)
    axes[1].plot(fpr, tpr, color='#5f396a', lw=2, label=f"ROC curve (area = {roc_auc:.2f})")
    axes[1].plot([0,1], [0,1], color='gray', lw=1, linestyle='--')
    axes[1].set_title(f"ROC Curve - {model_name}")
    axes[1].set_xlabel("False Positive Rate")
    axes[1].set_ylabel("True Positive Rate")
    axes[1].legend(loc="lower right")
  else:
    # Hide second subplot if probability estimates are not available
    axes[1].axis('off')

  plt.tight_layout()
  plt.show()

