"""Goal: compress or embed your data so you can see the “shape” of your patient space.

Note: used value of 15 for n_neighbors so its an in between

## **Clustering Benchmark/Segmentation**

**1) Cluster-Quality Scores**

**Inertia**

**Lower inertia** means your clusters are more compact (points sit close to their centers).

**Higher inertia** means clusters are looser or more spread out.

**Silhouette Score**

Think of each point asking: “Am I more similar to others in my own cluster, or to those in the nearest neighboring cluster?”

**High silhouette** means most points feel “right at home”—they’re close to neighbors in their cluster and clearly separated from the next‑closest group.

**Low or negative silhouette** means many points are straddling cluster borders or even nearer to a different cluster than their own.


**Calinski–Harabasz (CH) Index**

Imagine you shrink each cluster down to its “center” and look at how far apart those centers are versus how spread‑out each cluster is around its center.

**A higher CH** means clusters are both tight (points close to their own center) and well‑spaced apart from each other—like distinct, compact islands on a map.


**Davies–Bouldin (DB) Index**
Instead of averaging everything, DB focuses on the worst‑pair of clusters—the two that are hardest to tell apart.

**A low DB** means even your “least separable” pair of clusters still have good distance between them relative to how compact each is.

**A high DB** flags that at least one pair of clusters is too fuzzy or too close together.


**2) Stability Score**

**Mean Adjusted Rand Index**

If you shuffle the random seed or rerun the algorithm, will you get roughly the same grouping?

**A high ARI** means the cluster assignments are consistent every time you run it—your clusters aren’t just a fluke of initialization.

**A low ARI** means the algorithm is “wobbly”: small changes in the setup can send points hopping between clusters.

![Screenshot 2025-04-17 021225.png](data:image/png;base64,)

![image.png](data:image/png;base64,)
"""

def cluster_benchmark(
    X_train_unsupervised,
    transformer,
    algos,
    k_values,
    runs: int = 3,
    sample_size: int = 10000
) -> pd.DataFrame:
    """
    Benchmark clustering algorithms over multiple k values, with built-in preprocessing.
    """
    transformer_local = clone(transformer)
    X = transformer_local.fit_transform(X_train_unsupervised)
    records = []
    for name, Cls, param_grid in algos:
        sig = inspect.signature(Cls.__init__)
        accepts_rs = "random_state" in sig.parameters
        for params in param_grid:
            inertias, sils, chs, dbs, times = [], [], [], [], []
            labels_list = []
            for seed in range(runs):
                # only pass random_state if supported
                model = Cls(random_state=seed, **params) if accepts_rs else Cls(**params)
                t0 = time.time()
                labels = model.fit_predict(X) if hasattr(model, "fit_predict") else (model.fit(X), model.predict(X))[1]
                times.append(time.time() - t0)
                inertias.append(getattr(model, "inertia_", np.nan))
                try:
                    sils.append(
                        silhouette_score(
                            X, labels,
                            sample_size=min(sample_size, len(X)),
                            random_state=seed
                        )
                    )
                except ValueError:
                    sils.append(np.nan)
                chs.append(calinski_harabasz_score(X, labels))
                dbs.append(davies_bouldin_score(X, labels))
                labels_list.append(labels)

            base = labels_list[0]
            aris = [adjusted_rand_score(base, lab) for lab in labels_list[1:]] or [np.nan]
            counts = pd.Series(labels_list[0]).value_counts().sort_index()
            percs  = (counts / counts.sum() * 100).round(2)

            record = {
                "Algorithm": name,
                **params,
                "Mean Inertia":           np.mean(inertias),
                "Mean Silhouette":        np.nanmean(sils),
                "Mean Calinski–Harabasz": np.mean(chs),
                "Mean Davies–Bouldin":    np.mean(dbs),
                "Mean Runtime (s)":       np.mean(times),
                "Mean Stability (ARI)":   np.mean(aris),
                "Mean Distortion":        np.mean(inertias) / counts.sum()
            }
            for label, cnt in counts.items():
                record[f"count_{label}"] = cnt
                record[f"perc_{label}"]  = percs[label]
            records.append(record)

    return pd.DataFrame(records)

# Simple wrapper
def run_clustering_benchmark(X, algos, k_values, runs=3, sample_size=10000):
    return cluster_benchmark(
        X_train_unsupervised=X,
        transformer=Pipeline([("passthrough", FunctionTransformer(lambda x: x))]),
        algos=algos,
        k_values=k_values,
        runs=runs,
        sample_size=sample_size
    )

